options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
try {
  const root = htmlNode;

  function getSeries(refId) {
    return (data.series || []).find(s => String(s.refId).toUpperCase() === refId);
  }

  function getSeriesAll(refId) {
    return (data.series || []).filter(s => String(s.refId).toUpperCase() === refId);
  }

  function field(series, name) {
    return series?.fields?.find(f => f.name === name) || null;
  }

  function arr(f) {
    if (!f) return [];
    if (f.values?.toArray) return f.values.toArray();
    if (f.values?.buffer) return Array.from(f.values.buffer);
    if (f.values?.get) {
      let out = [];
      for (let i = 0; i < f.values.length; i++) out.push(f.values.get(i));
      return out;
    }
    return Array.isArray(f.values) ? f.values : [];
  }

  function resetAllCAAValues() {
    root.querySelectorAll(".tank-card .metric strong").forEach(el => el.textContent = "--");
    root.querySelectorAll(".tank-card .metric").forEach(m => {
      m.classList.remove("good", "danger");
      m.classList.add("neutral");
    });
    root.querySelectorAll(".trend-last").forEach(el => {
      el.textContent = "LAST: --";
      el.classList.remove("danger");
    });
    root.querySelectorAll(".trend-chart").forEach(el => el.innerHTML = "");
  }

  resetAllCAAValues();

  function setMetric(card, labelText, valueText, state = "neutral") {
    if (!card) return;
    const m = [...card.querySelectorAll(".metric")].find(x =>
      String(x.querySelector("span")?.textContent || "")
        .toUpperCase()
        .includes(labelText.toUpperCase())
    );
    if (!m) return;

    m.classList.remove("good", "danger", "neutral");
    m.classList.add(state);

    const strong = m.querySelector("strong");
    if (strong) strong.textContent = valueText;
  }

  function disableMetric(card, labelText) {
    setMetric(card, labelText, "--", "neutral");
  }

  function greyUnusedMetric(card, labelText) {
    if (!card) return;

    const metric = [...card.querySelectorAll(".metric")].find(m =>
      String(m.querySelector("span")?.textContent || "")
        .toUpperCase()
        .includes(labelText.toUpperCase())
    );

    if (!metric) return;

    metric.classList.remove("good", "danger");
    metric.classList.add("neutral");

    // CDS-style grey
    metric.style.background = "linear-gradient(180deg, #5f6979, #4f5968)";
    metric.style.border = "1px solid #cfd6df";
    metric.style.boxShadow = "none";
    metric.style.opacity = "0.75";

    const span = metric.querySelector("span");
    const strong = metric.querySelector("strong");

    if (span) span.style.color = "#d9dee6";
    if (strong) {
      strong.textContent = "--";
      strong.style.color = "#f1f4f7";
    }
  }

  function disableTankCard(card) {
    if (!card) return;
    card.style.opacity = "0.48";

    card.querySelectorAll(".metric").forEach(m => {
      m.classList.remove("good", "danger");
      m.classList.add("neutral");
      const strong = m.querySelector("strong");
      if (strong) strong.textContent = "--";
    });

    const fill = card.querySelector(".tank-fill");
    if (fill) {
      fill.classList.remove("green-fill", "red-fill");
      fill.classList.add("red-fill");
      fill.style.height = "0%";
      fill.style.opacity = "0.35";
    }

    const badge = card.querySelector(".tank-badge");
    if (badge) {
      badge.classList.remove("running");
      badge.classList.add("standby");
      badge.textContent = "--";
    }
  }

  function getTankCard(titleText) {
    return [...root.querySelectorAll(".tank-card")].find(card =>
      String(card.querySelector(".tank-name")?.textContent || "")
        .trim()
        .toUpperCase() === titleText.toUpperCase()
    );
  }

  const acidT1 = getTankCard("DILUTED ACID T1");
  const acidT2 = getTankCard("DILUTED ACID T2");
  const acidCon1 = getTankCard("CONCENTRATED ACID T1");
  const acidCon2 = getTankCard("CONCENTRATED ACID T2");

  const alkT1 = getTankCard("DILUTED ALKALINE T1");
  const alkT2 = getTankCard("DILUTED ALKALINE T2");
  const alkCon1 = getTankCard("CONCENTRATED ALKALINE T1");


  [acidCon1, acidCon2, alkCon1].forEach(card => {
    if (!card) return;

    card.style.opacity = "1";


    card.querySelectorAll(".metric").forEach(m => {
      m.classList.remove("good", "danger");
      m.classList.add("neutral");
      const strong = m.querySelector("strong");
      if (strong) strong.textContent = "--";
    });


    const fill = card.querySelector(".tank-fill");
    if (fill) fill.style.opacity = "1";

    const center = card.querySelector(".tank-center-value");
    if (center) center.style.opacity = "1";
  });

  [
    acidT1,
    acidT2,
    acidCon1,
    acidCon2,
    alkT1,
    alkT2,
    alkCon1
  ].forEach(card => {
    greyUnusedMetric(card, "PUMP SPEED");
    greyUnusedMetric(card, "STATUS");
  });



  const acidLatest = getSeries("A");
  const alkLatest = getSeries("C");
  const acidTrend = getSeriesAll("B");
  const alkTrend = getSeriesAll("D");
  const levelPressureLatest = getSeriesAll("E");
  const levelTrend = getSeriesAll("F");

  function getLevelPressureMap(seriesInput) {
    const seriesList = Array.isArray(seriesInput) ? seriesInput : [seriesInput];
    const map = {};

    seriesList.forEach(series => {
      if (!series) return;

      const valueField =
        field(series, "value") ||
        series.fields.find(f => f.type === "number");

      if (!valueField) return;

      const itemField = field(series, "item");
      const values = arr(valueField);
      const items = arr(itemField);

      for (let i = 0; i < values.length; i++) {
        let item = String(items[i] || "").toUpperCase();

        if (!item) {
          item = String(
            valueField.labels?.item ||
            valueField.config?.displayNameFromDS ||
            series.name ||
            ""
          ).toUpperCase();
        }

        if (item.includes("CON_ACID_T1")) item = "CON_ACID_T1";
        if (item.includes("CON_ACID_T2")) item = "CON_ACID_T2";
        if (item.includes("DIL_ACID_T1")) item = "DIL_ACID_T1";
        if (item.includes("DIL_ACID_T2")) item = "DIL_ACID_T2";
        if (item.includes("CON_ALK_T1")) item = "CON_ALK_T1";
        if (item.includes("DIL_ALK_T1")) item = "DIL_ALK_T1";
        if (item.includes("DIL_ALK_T2")) item = "DIL_ALK_T2";
        if (item.includes("ACID_SUPPLY")) item = "ACID_SUPPLY";
        if (item.includes("ALK_SUPPLY")) item = "ALK_SUPPLY";

        if (item) map[item] = Number(values[i]);
      }
    });

    return map;
  }

  function noDataTank(card) {
    if (!card) return;

    setMetric(card, "LEVEL", "--", "neutral");

    const fill = card.querySelector(".tank-fill");
    if (fill) {
      fill.style.height = "0%";
      fill.style.opacity = "0.2";
      fill.classList.remove("green-fill", "red-fill");
    }
  }

  function applyLevel(card, levelValue) {
    if (!card) return;

    if (!Number.isFinite(levelValue)) {
      noDataTank(card);
      return;
    }

    const isLow = levelValue < 75;

    setMetric(card, "LEVEL", `${Math.round(levelValue)} CM`, isLow ? "danger" : "good");

    const fill = card.querySelector(".tank-fill");
    if (fill) {
      const pct = Math.max(0, Math.min(100, (levelValue / 560) * 100));
      fill.style.height = `${pct}%`;
      fill.style.opacity = "1";
      fill.classList.remove("green-fill", "red-fill");
      fill.classList.add(isLow ? "red-fill" : "green-fill");
    }
  }

  function applyLatest(series, tankMap, valueFieldName) {
    if (!series) return;

    const tankField = field(series, "tankNo");
    const valField = field(series, valueFieldName);
    const minField = field(series, valueFieldName.replace("_current", "_min"));
    const maxField = field(series, valueFieldName.replace("_current", "_max"));
    const statusField = field(series, "status");

    if (!valField) return;

    const tanks = arr(tankField);
    const vals = arr(valField);
    const mins = arr(minField);
    const maxs = arr(maxField);
    const statuses = arr(statusField);

    for (let i = 0; i < vals.length; i++) {
      let tankNo = String(tanks[i] || "").toUpperCase();

      if (!tankNo) {
        tankNo = String(
          valField.labels?.tankNo ||
          valField.config?.displayNameFromDS ||
          series.name ||
          ""
        ).toUpperCase();
      }

      const isAcid = valueFieldName.includes("acid");
      const isAlk = valueFieldName.includes("alkaline");

      if (tankNo === "1") tankNo = isAcid ? "ACID1" : isAlk ? "ALK1" : tankNo;
      if (tankNo === "2") tankNo = isAcid ? "ACID2" : isAlk ? "ALK2" : tankNo;

      if (tankNo.includes("ACID1")) tankNo = "ACID1";
      if (tankNo.includes("ACID2")) tankNo = "ACID2";
      if (tankNo.includes("ALK1")) tankNo = "ALK1";
      if (tankNo.includes("ALK2")) tankNo = "ALK2";
      const card = tankMap[tankNo];
      if (!card) continue;

      const val = Number(vals[i]);
      const min = Number(mins[i]);
      const max = Number(maxs[i]);
      const status = Number(statuses[i]);

      const bad = status === 2 || (
        Number.isFinite(val) &&
        Number.isFinite(min) &&
        Number.isFinite(max) &&
        (val < min || val > max)
      );


      const ok = status === 1 && !bad;



      setMetric(
        card,
        valueFieldName.includes("acid") ? "ACID STRENGTH" : "ALKALINE STRENGTH",
        Number.isFinite(val) ? val.toFixed(2) : "--",
        bad ? "danger" : ok ? "good" : "neutral"
      );

      const fill = card.querySelector(".tank-fill");
      if (fill) {
        fill.classList.remove("green-fill", "red-fill");
        fill.classList.add(bad ? "red-fill" : "green-fill");
        fill.style.height = "0%";
        fill.style.opacity = "0.35";
      }
    }
  }

  applyLatest(acidLatest, { ACID1: acidT1, ACID2: acidT2 }, "acid_current");
  applyLatest(alkLatest, { ALK1: alkT1, ALK2: alkT2 }, "alkaline_current");

  const lp = getLevelPressureMap(levelPressureLatest);

  applyLevel(acidCon1, lp.CON_ACID_T1);
  applyLevel(acidCon2, lp.CON_ACID_T2);
  applyLevel(acidT1, lp.DIL_ACID_T1);
  applyLevel(acidT2, lp.DIL_ACID_T2);

  applyLevel(alkCon1, lp.CON_ALK_T1);
  applyLevel(alkT1, lp.DIL_ALK_T1);
  applyLevel(alkT2, lp.DIL_ALK_T2);

  function buildRows(seriesInput, valueKey, minKey, maxKey) {
    const seriesList = Array.isArray(seriesInput) ? seriesInput : [seriesInput];
    const out = {};

    seriesList.forEach(series => {
      if (!series) return;

      const timeField =
        field(series, "_time") ||
        field(series, "Time") ||
        series.fields.find(f => f.type === "time");

      const valField = field(series, valueKey);
      const minField = field(series, minKey);
      const maxField = field(series, maxKey);
      const tankField = field(series, "tankNo");

      if (!valField) return;

      const times = arr(timeField);
      const vals = arr(valField);
      const mins = arr(minField);
      const maxs = arr(maxField);
      const tanks = arr(tankField);

      for (let i = 0; i < vals.length; i++) {
        let tankNo = String(tanks[i] || "").toUpperCase();

        if (!tankNo) {
          tankNo = String(
            valField.labels?.tankNo ||
            valField.config?.displayNameFromDS ||
            series.name ||
            ""
          ).toUpperCase();
        }

        const isAcid = valueKey.includes("acid");
        const isAlk = valueKey.includes("alkaline");

        if (tankNo === "1") tankNo = isAcid ? "ACID1" : isAlk ? "ALK1" : tankNo;
        if (tankNo === "2") tankNo = isAcid ? "ACID2" : isAlk ? "ALK2" : tankNo;

        if (tankNo.includes("ACID1")) tankNo = "ACID1";
        if (tankNo.includes("ACID2")) tankNo = "ACID2";
        if (tankNo.includes("ALK1")) tankNo = "ALK1";
        if (tankNo.includes("ALK2")) tankNo = "ALK2";

        if (!tankNo) continue;
        if (!out[tankNo]) out[tankNo] = [];

        out[tankNo].push({
          time: times[i],
          [valueKey]: vals[i],
          [minKey]: mins[i],
          [maxKey]: maxs[i]
        });
      }
    });

    return out;
  }

  function buildLevelRows(seriesInput) {
    const seriesList = Array.isArray(seriesInput) ? seriesInput : [seriesInput];
    const out = {};

    seriesList.forEach(series => {
      if (!series) return;
      const timeField = field(series, "_time") || field(series, "Time") || series.fields.find(f => f.type === "time");
      const valueField = field(series, "level_current") || field(series, "value");
      const itemField = field(series, "item");
      if (!timeField || !valueField) return;

      const times = arr(timeField);
      const values = arr(valueField);
      const items = arr(itemField);
      for (let i = 0; i < values.length; i++) {
        let item = String(items[i] || valueField.labels?.item || valueField.config?.displayNameFromDS || series.name || "").toUpperCase();
        const itemMatch = item.match(/DIL_(?:ACID|ALK)_T[12]/);
        if (!itemMatch) continue;
        item = itemMatch[0];
        if (!out[item]) out[item] = [];
        out[item].push({
          time: times[i],
          level_current: values[i],
          level_min: 0,
          level_max: 560
        });
      }
    });
    return out;
  }

  function renderTrend(chartEl, lastEl, rows, valueKey, minKey, maxKey, unit, yAxisLabel, labels) {
    if (!chartEl) return;

    let normalized = rows.map(row => {
      const numericTime = Number(row.time);
      const time = Number.isFinite(numericTime) ? numericTime : new Date(row.time).getTime();
      const value = Number(row[valueKey]);
      const rawMin = Number(row[minKey]);
      const rawMax = Number(row[maxKey]);
      return {
        t: time,
        v: value,
        lo: Number.isFinite(rawMin) ? rawMin : value,
        hi: Number.isFinite(rawMax) ? rawMax : value
      };
    })
    .filter(row => Number.isFinite(row.t) && Number.isFinite(row.v))
    .sort((a, b) => a.t - b.t);

    if (!normalized.length) {
      chartEl.innerHTML = '<div class="trend-empty">NO TREND DATA</div>';
      if (lastEl) {
        lastEl.textContent = "LAST: --";
        lastEl.classList.remove("danger");
      }
      return;
    }

    const tArr = normalized.map(row => row.t);
    const vArr = normalized.map(row => row.v);
    const loArr = normalized.map(row => row.lo);
    const hiArr = normalized.map(row => row.hi);
    const N = normalized.length;
    const W = chartEl.clientWidth || 560;
    const H = chartEl.clientHeight || 220;
    if (W < 50 || H < 50) {
      chartEl.innerHTML = "";
      return;
    }

    const padL = 72, padR = 58, padT = 42, padB = 54;
    const innerW = W - padL - padR;
    const innerH = H - padT - padB;
    let yMin = Math.min(...loArr, ...vArr);
    let yMax = Math.max(...hiArr, ...vArr);
    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }
    if (yAxisLabel === "cm") {
      yMin = 0;
      yMax = Math.max(560, yMax);
    } else {
      const range = yMax - yMin;
      const targetRange = 0.08;
      if (range < targetRange) {
        const center = (yMax + yMin) / 2;
        yMin = center - targetRange / 2;
        yMax = center + targetRange / 2;
      } else {
        const padding = range * 0.05;
        yMin -= padding;
        yMax += padding;
      }
    }

    const tMin = tArr[0];
    const tMax = tArr[tArr.length - 1];
    const xTs = timestamp => N === 1 || tMax === tMin
      ? padL + innerW / 2
      : padL + ((timestamp - tMin) / (tMax - tMin)) * innerW;
    const x = index => xTs(tArr[index]);
    const y = value => padT + (1 - (value - yMin) / (yMax - yMin)) * innerH;
    const fmtTime = time => new Date(time).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    const buildPath = values => {
      if (N === 1) return `M ${padL} ${y(values[0]).toFixed(2)} L ${W - padR} ${y(values[0]).toFixed(2)}`;
      return values.map((value, index) => `${index ? "L" : "M"} ${x(index).toFixed(2)} ${y(value).toFixed(2)}`).join(" ");
    };

    const yTicks = Array.from({ length: 5 }, (_, index) => yMin + (index / 4) * (yMax - yMin));
    const xTickTs = [...new Set([tMin, tMin + ((tMax - tMin) / 2), tMax])];
    const lastValue = vArr[N - 1];
    const lastMin = loArr[N - 1];
    const lastMax = hiArr[N - 1];
    if (lastEl) {
      lastEl.textContent = `LAST: ${lastValue.toFixed(2)}${unit}`;
      lastEl.classList.toggle("danger", lastValue < lastMin || lastValue > lastMax);
    }

    const clampY = value => Math.max(padT + 12, Math.min(H - padB - 10, value));
    const labelIndex = Math.min(1, N - 1);
    const labelX = padL + 10;
    const yMinLabel = clampY(y(loArr[labelIndex]) - 4);
    const yMaxLabel = clampY(y(hiArr[labelIndex]) - 6);
    const lastX = x(N - 1);
    const lastY = y(lastValue);
    const colorActual = "rgba(88,166,255,0.95)";
    const colorMinMax = "rgba(125,196,255,0.82)";
    const colorGrid = "rgba(255,255,255,0.08)";
    const colorAxis = "rgba(255,255,255,0.10)";
    const colorText = "rgba(210,225,245,0.78)";

    chartEl.innerHTML = `
      <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" aria-label="Interactive ${labels.value} trend">
        <text class="axis-unit axis-title axis-title-y" x="20" y="26" text-anchor="start">${yAxisLabel}</text>
        ${yTicks.map(value => {
          const tickY = y(value);
          return `
            <line x1="${padL}" y1="${tickY}" x2="${W - padR}" y2="${tickY}" stroke="${colorGrid}" stroke-width="1"/>
            <text class="axis-tick axis-tick-y" x="${padL - 8}" y="${tickY + 4}" text-anchor="end" fill="${colorText}" font-size="14" font-weight="1000">${value.toFixed(2)}</text>
          `;
        }).join("")}
        <line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="${colorAxis}" stroke-width="1"/>
        ${xTickTs.map(timestamp => `
          <text class="axis-tick axis-tick-x" x="${xTs(timestamp)}" y="${H - 30}" text-anchor="middle" fill="${colorText}" font-size="13" font-weight="1000">${fmtTime(timestamp)}</text>
        `).join("")}
        <text class="axis-unit axis-title axis-title-x" x="${padL + innerW / 2}" y="${H - 8}" text-anchor="middle">Time</text>
        <path d="${buildPath(loArr)}" fill="none" stroke="${colorMinMax}" stroke-width="1.7" stroke-dasharray="5 4"></path>
        <path d="${buildPath(hiArr)}" fill="none" stroke="${colorMinMax}" stroke-width="1.7" stroke-dasharray="5 4"></path>
        <path d="${buildPath(vArr)}" fill="none" stroke="${colorActual}" stroke-width="3.2"></path>
        <rect class="hover-capture" x="${padL}" y="${padT}" width="${innerW}" height="${innerH}" fill="transparent" pointer-events="all"/>
        <text class="limit-label" x="${labelX}" y="${yMinLabel}" fill="${colorMinMax}" font-size="12" font-weight="1000">${labels.min}</text>
        <text class="limit-label" x="${labelX}" y="${yMaxLabel}" fill="${colorMinMax}" font-size="12" font-weight="1000">${labels.max}</text>
        <circle cx="${lastX}" cy="${lastY}" r="3.3" fill="${colorActual}"/>
        <text class="chart-value-label" x="${Math.min(lastX - 8, W - 8)}" y="${lastY - 8}" text-anchor="end" fill="rgba(240,247,255,0.96)" font-size="12" font-weight="1000">${lastValue.toFixed(2)}${unit}</text>
        <line class="hover-line" x1="0" y1="${padT}" x2="0" y2="${H - padB}" stroke="rgba(255,255,255,0.35)" stroke-width="1" stroke-dasharray="4 4" style="display:none"/>
        <circle class="hover-dot" cx="0" cy="0" r="4" fill="${colorActual}" stroke="#fff" stroke-width="1.5" style="display:none"/>
        <g class="hover-tip" style="display:none">
          <filter id="tooltipShadow" x="-20%" y="-20%" width="140%" height="140%"><feDropShadow dx="0" dy="3" stdDeviation="4" flood-color="#000000" flood-opacity="0.75"/></filter>
          <rect width="230" height="104" rx="12" fill="rgba(8,18,34,0.98)" stroke="rgba(88,166,255,0.95)" stroke-width="1.2" filter="url(#tooltipShadow)"/>
          <rect width="230" height="38" rx="12" fill="rgba(25,85,150,0.88)"/>
          <text class="hover-time" x="12" y="17" fill="#ffffff" font-size="14" font-weight="1000"></text>
          <text class="hover-date" x="12" y="34" fill="#ffffff" font-size="12" font-weight="900"></text>
          <circle cx="15" cy="60" r="5" fill="${colorActual}"/>
          <text class="hover-val" x="28" y="65" fill="#ffffff" font-size="16" font-weight="1000"></text>
          <text class="hover-range" x="12" y="88" fill="#bfe2ff" font-size="13" font-weight="900"></text>
        </g>
      </svg>
    `;

    const svg = chartEl.querySelector("svg");
    if (!svg) return;
    const hoverLine = svg.querySelector(".hover-line");
    const hoverDot = svg.querySelector(".hover-dot");
    const hoverTip = svg.querySelector(".hover-tip");
    const hoverTime = svg.querySelector(".hover-time");
    const hoverDate = svg.querySelector(".hover-date");
    const hoverValue = svg.querySelector(".hover-val");
    const hoverRange = svg.querySelector(".hover-range");

    svg.addEventListener("mousemove", event => {
      const bounds = svg.getBoundingClientRect();
      const mouseX = ((event.clientX - bounds.left) / bounds.width) * W;
      let index = 0;
      let bestDistance = Infinity;
      for (let i = 0; i < N; i++) {
        const distance = Math.abs(x(i) - mouseX);
        if (distance < bestDistance) {
          bestDistance = distance;
          index = i;
        }
      }
      const pointX = x(index);
      const pointY = y(vArr[index]);
      hoverLine.setAttribute("x1", pointX);
      hoverLine.setAttribute("x2", pointX);
      hoverLine.style.display = "";
      hoverDot.setAttribute("cx", pointX);
      hoverDot.setAttribute("cy", pointY);
      hoverDot.style.display = "";

      const tipWidth = 230;
      const tipHeight = 104;
      let tipX = pointX + 10;
      let tipY = pointY - tipHeight;
      if (tipX + tipWidth > W - 5) tipX = pointX - tipWidth - 10;
      if (tipY < padT + 5) tipY = pointY + 14;
      if (tipY + tipHeight > H - padB) tipY = H - padB - tipHeight - 5;
      hoverTip.setAttribute("transform", `translate(${tipX},${tipY})`);
      hoverTip.style.display = "";
      hoverTime.textContent = fmtTime(tArr[index]);
      hoverDate.textContent = new Date(tArr[index]).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
      hoverValue.textContent = `${vArr[index].toFixed(2)}${unit}`;
      hoverRange.textContent = `Min ${loArr[index].toFixed(2)}  Max ${hiArr[index].toFixed(2)}`;
    });
    svg.addEventListener("mouseleave", () => {
      hoverLine.style.display = "none";
      hoverDot.style.display = "none";
      hoverTip.style.display = "none";
    });
  }

  const trendCards = [...root.querySelectorAll(".trend-card")];

  function trendByTitle(...terms) {
    return trendCards.find(card => {
      const title = String(card.querySelector(".trend-title")?.textContent || "").toUpperCase();
      return terms.every(term => title.includes(term.toUpperCase()));
    });
  }

  const acidRows = buildRows(acidTrend, "acid_current", "acid_min", "acid_max");
  const alkalineRows = buildRows(alkTrend, "alkaline_current", "alkaline_min", "alkaline_max");
  const levelRows = buildLevelRows(levelTrend);
  const strengthLabels = { value: "Strength", min: "Min", max: "Max" };
  const levelLabels = { value: "Level", min: "Min 0", max: "Max 560" };

  renderTrend(trendByTitle("DILUTED ACID T1", "STRENGTH")?.querySelector(".trend-chart"), trendByTitle("DILUTED ACID T1", "STRENGTH")?.querySelector(".trend-last"), acidRows.ACID1 || [], "acid_current", "acid_min", "acid_max", "%", "%", strengthLabels);
  renderTrend(trendByTitle("DILUTED ACID T2", "STRENGTH")?.querySelector(".trend-chart"), trendByTitle("DILUTED ACID T2", "STRENGTH")?.querySelector(".trend-last"), acidRows.ACID2 || [], "acid_current", "acid_min", "acid_max", "%", "%", strengthLabels);
  renderTrend(trendByTitle("DILUTED ALKALINE T1", "STRENGTH")?.querySelector(".trend-chart"), trendByTitle("DILUTED ALKALINE T1", "STRENGTH")?.querySelector(".trend-last"), alkalineRows.ALK1 || [], "alkaline_current", "alkaline_min", "alkaline_max", "%", "%", strengthLabels);
  renderTrend(trendByTitle("DILUTED ALKALINE T2", "STRENGTH")?.querySelector(".trend-chart"), trendByTitle("DILUTED ALKALINE T2", "STRENGTH")?.querySelector(".trend-last"), alkalineRows.ALK2 || [], "alkaline_current", "alkaline_min", "alkaline_max", "%", "%", strengthLabels);
  renderTrend(trendByTitle("DILUTED ACID T1", "LEVEL")?.querySelector(".trend-chart"), trendByTitle("DILUTED ACID T1", "LEVEL")?.querySelector(".trend-last"), levelRows.DIL_ACID_T1 || [], "level_current", "level_min", "level_max", " cm", "cm", levelLabels);
  renderTrend(trendByTitle("DILUTED ACID T2", "LEVEL")?.querySelector(".trend-chart"), trendByTitle("DILUTED ACID T2", "LEVEL")?.querySelector(".trend-last"), levelRows.DIL_ACID_T2 || [], "level_current", "level_min", "level_max", " cm", "cm", levelLabels);
  renderTrend(trendByTitle("DILUTED ALKALINE T1", "LEVEL")?.querySelector(".trend-chart"), trendByTitle("DILUTED ALKALINE T1", "LEVEL")?.querySelector(".trend-last"), levelRows.DIL_ALK_T1 || [], "level_current", "level_min", "level_max", " cm", "cm", levelLabels);
  renderTrend(trendByTitle("DILUTED ALKALINE T2", "LEVEL")?.querySelector(".trend-chart"), trendByTitle("DILUTED ALKALINE T2", "LEVEL")?.querySelector(".trend-last"), levelRows.DIL_ALK_T2 || [], "level_current", "level_min", "level_max", " cm", "cm", levelLabels);


} catch (err) {
  console.log("CAA detail dashboard render error:", err);
}
